#!/usr/bin/env bash
# Querencia Linux -- Flatpak + Flathub
# Installs Flatpak and configures Flathub remote via static config.
# The remote is declared in /usr/lib/flatpak/remotes.d/ so it survives
# the /var cleanup that happens at the end of the container build.
# Warehouse (Flatpak Store GUI) is installed per-user at first boot.
set -xeuo pipefail

dnf install -y flatpak

# Static Flathub remote config (survives /var wipe)
mkdir -p /usr/lib/flatpak/remotes.d
cat > /usr/lib/flatpak/remotes.d/flathub.flatpakrepo <<'REPO'
[Flatpak Repo]
Title=Flathub
Url=https://dl.flathub.org/repo/
Homepage=https://flathub.org/
Comment=Central repository of Flatpak applications
Description=Central repository of Flatpak applications
Icon=https://dl.flathub.org/repo/logo.svg

REPO

echo "Flatpak installed. Flathub remote configured via static config."
